SQLLite.SQL:
UPDATE CASE_EVENTS CE
SET    CE.DELETED_FLAG = 'Y'
WHERE  CE.EVENT_SEQ = (
	   SELECT MAX(CE2.EVENT_SEQ) 
	   FROM   CASE_EVENTS CE2
	   WHERE  CE2.CASE_NUMBER = ${param.caseNumber}
	   AND    CE2.PARTY_ROLE_CODE = ${param.partyRoleCode}
	   AND    CE2.CASE_PARTY_NO = ${param.casePartyNumber}
	   AND    CE2.STD_EVENT_ID = ${param.stdEventId}
	   AND    CE2.DELETED_FLAG = 'N')
